SELECT n.notification_id, n.message, n.notification_time
FROM notifications n
JOIN statistical_analysis sa ON n.user_id = sa.reviewed_by;

SELECT patient_data.patient_id, patients.first_name, patients.last_name, patient_data.rmse, patient_data.mav, patient_data.var
FROM patient_data
JOIN patients ON patient_data.patient_id = patients.patient_id;

SELECT username, last_login
FROM user_accounts
ORDER BY last_login DESC;

SELECT COUNT(DISTINCT patient_id)
FROM (
    SELECT patient_id 
    FROM patients
    WHERE patient_id IN (
        SELECT patient_id 
        FROM clinical_trials 
        WHERE trial_name = 'Trial B'
    )
) AS patient_in_trial;

SELECT ua.*
FROM user_accounts ua
JOIN statistical_analysis sa ON ua.username = sa.reviewed_by;
